import 'package:equatable/equatable.dart'; import '../../../../core/utils/date_parser.dart'; import '../../../../core/utils/enum_parser.dart'; import '../../../../core/utils/map_utils.dart';
enum AppNotificationType{chat,product,favorite,review,report,system,promotion}
class AppNotification extends Equatable{final String id,userId,title,body; final AppNotificationType type; final String? referenceId; final bool isRead; final DateTime createdAt; const AppNotification({required this.id,required this.userId,required this.title,required this.body,this.type=AppNotificationType.system,this.referenceId,this.isRead=false,required this.createdAt}); factory AppNotification.fromMap(String id,Map<String,dynamic> map)=>AppNotification(id:id,userId:MapUtils.stringValue(map,'userId'),title:MapUtils.stringValue(map,'title'),body:MapUtils.stringValue(map,'body'),type:EnumParser.fromName(values:AppNotificationType.values,name:map['type'] as String?,fallback:AppNotificationType.system),referenceId:map['referenceId'] as String?,isRead:MapUtils.boolValue(map,'isRead'),createdAt:DateParser.fromValue(map['createdAt'])??DateTime.now()); Map<String,dynamic> toMap()=>{'userId':userId,'title':title,'body':body,'type':type.name,'referenceId':referenceId,'isRead':isRead,'createdAt':createdAt.toIso8601String()}; @override List<Object?> get props=>[id,userId,title,body,type,referenceId,isRead,createdAt];}
